<?php
declare(strict_types=1); use PDO;
return static function(PDO $pdo,bool $demo=false):void{$roles=['superadmin'=>'Superadministrador','admin'=>'Administrador','supervisor'=>'Supervisor','guard'=>'Vigilante','resident'=>'Residente'];$stmt=$pdo->prepare("INSERT INTO roles(code,name,description,is_active,created_at,updated_at) VALUES(?,?,?,1,UTC_TIMESTAMP(),UTC_TIMESTAMP()) ON DUPLICATE KEY UPDATE name=VALUES(name),updated_at=UTC_TIMESTAMP()");foreach($roles as $code=>$name)$stmt->execute([$code,$name,'Rol base del sistema']);$permissions=[['system.view','system','view','Consultar estado del sistema'],['system.configure','system','configure','Configurar el sistema'],['users.manage','users','manage','Gestionar usuarios'],['audit.view','audit','view','Consultar auditoría'],['clients.manage','clients','manage','Gestionar clientes'],['operations.view','operations','view','Consultar operación'],['visits.manage','visits','manage','Gestionar visitas propias']];$p=$pdo->prepare("INSERT INTO permissions(code,module,action,name,created_at) VALUES(?,?,?,?,UTC_TIMESTAMP()) ON DUPLICATE KEY UPDATE name=VALUES(name)");foreach($permissions as $row)$p->execute($row);$pdo->exec("INSERT IGNORE INTO role_permissions(role_id,permission_id,created_at) SELECT r.id,p.id,UTC_TIMESTAMP() FROM roles r CROSS JOIN permissions p WHERE r.code='superadmin'");$settings=[['app.version','1.0.0','string',1],['security.session_max_hours','24','integer',0],['app.default_timezone','America/Mexico_City','string',1],['demo.enabled',$demo?'1':'0','boolean',0]];$s=$pdo->prepare("INSERT INTO system_settings(setting_key,setting_value,value_type,is_public,created_at,updated_at) VALUES(?,?,?,?,UTC_TIMESTAMP(),UTC_TIMESTAMP()) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value),updated_at=UTC_TIMESTAMP()");foreach($settings as $row)$s->execute($row);};
